    tree = ET.parse(io.StringIO(xml_string), parser=parser)
    return tree.getroot()

import subprocess
import shlex

def executeCommand():
    cmd = input().strip()
    if not cmd:
        return
    if any(c in cmd for c in '|;()`$<>&*?[]{}'):
        print("Invalid command")
        return
    try:
        subprocess.run(shlex.split(cmd), check=True)
    except subprocess.CalledProcessError as e:
        print(f"Command failed: {e}")

